async (page) => {
  var title = "图解 Blaze · 第 21 章 · SQL 优化与实战模式 — 图解 Blaze-Persistence";
  var html = "<section style=\"margin-bottom:24px;\">\n<h2 style=\"font-size:24px;font-weight:800;color:#1a1a2e;line-height:1.4;margin:0 0 8px;\">第 21 章 · SQL 优化与实战模式</h2>\n</section>\n<section><p style=\"font-size:14px;color:#888;margin-bottom:28px;line-height:1.7;\">获取策略 · N+1 检测 · 分页优化 · CTE 优化 · 批量 DML · 全文搜索 · 软删除 · 多租户 · 树形结构</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px 14px;margin:0 0 28px;line-height:1.9;\"><p style=\"font-size:15px;color:#2b2b2b;margin-bottom:10px;line-height:1.8;\">前 20 章构建了完整的 Blaze-Persistence 知识体系——从 CriteriaBuilder 到 Entity View，从 CTE 到窗口函数，从渲染管线到扩展 SPI。但在生产环境中，正确使用 API 只是起点——如何让查询<strong style=\"color:#1a1a2e;font-weight:700;\">快</strong>、让代码<strong style=\"color:#1a1a2e;font-weight:700;\">简洁</strong>、让架构<strong style=\"color:#1a1a2e;font-weight:700;\">可维护</strong>，才是衡量工程水平的标尺。本章汇聚 9 类实战优化模式，每个模式都遵循「问题 → 解决方案 → 生成 SQL → 原理解读」四步法。</p><ul style=\"margin:8px 0 8px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:4px;font-size:13px;\">获取优化：Entity View 精确投影 · N+1 三种消除策略 · Keyset 分页</li><li style=\"margin-bottom:4px;font-size:13px;\">高级查询：CTE + 窗口函数报表 · 全文搜索 · 递归 CTE 树形结构</li><li style=\"margin-bottom:4px;font-size:13px;\">写入与治理：批量 DML 优化 · <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@ViewFilter</code> 软删除/多租户 · 性能调优清单</li></ul><p style=\"font-size:12px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">前置知识：<span style=\"color:#1e6fff;\">第 4 章 · Entity View</span> 的投影概念，<span style=\"color:#1e6fff;\">第 8 章 · CTE</span> 的公用表表达式，<span style=\"color:#1e6fff;\">第 9 章 · 窗口函数</span>，<span style=\"color:#1e6fff;\">第 10 章 · 分页</span>，<span style=\"color:#1e6fff;\">第 11 章 · DML</span>，以及 <span style=\"color:#1e6fff;\">第 20 章 · 扩展体系</span> 中的 JpqlFunction 和 ViewFilter。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-1 SQL 优化与实战模式全景图</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n① 获取优化\n• Entity View 精确投影<br/>SELECT 3 列 vs SELECT *<br/>• N+1 检测与消除<br/>BatchFetch / Correlated\n\n\n② 分页优化\n• OFFSET 分页<br/>扫描 N 行丢弃<br/>• Keyset 分页<br/>WHERE id > ? 恒定 O(1)\n\n\n③ 复杂查询\n• CTE 月度排名<br/>窗口函数 + 聚合<br/>• 报表查询<br/>移动平均 / 累计<br/>• 递归 CTE<br/>树形结构查询\n\n\n④ 批量 DML\n• 批量 UPDATE<br/>一条语句更新 N 行<br/>• 批量 DELETE<br/>一条语句清理历史<br/>• INSERT...SELECT<br/>归档数据迁移\n\n\n⑤ 实战模式\n• 软删除<br/>@ViewFilter 透明过滤<br/>• 多租户<br/>租户条件自动注入<br/>• 全文搜索<br/>自定义 JpqlFunction\n\n</p></section>\n<section style=\"margin:12px 0 20px;\"><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">9</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">优化模式</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">3x–100x</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">典型性能提升</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">0</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">额外依赖</p></section><section style=\"display:inline-block;min-width:100px;background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:12px 14px;text-align:center;margin:4px 6px 4px 0;\"><p style=\"margin:0;font-size:22px;font-weight:800;color:#1e6fff;\">100%</p><p style=\"margin:4px 0 0;font-size:10px;color:#888;text-transform:uppercase;letter-spacing:.5px;\">数据库可移植</p></section></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.1 Entity View 获取策略优化</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">最简单也最有效的优化——从 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT *</code> 到<strong style=\"color:#1a1a2e;font-weight:700;\">精确投影</strong>。当业务只需要 3 个字段时，查询 15+ 列不仅浪费带宽，还会阻止数据库使用覆盖索引。Entity View 自动裁剪查询列。</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">问题：SELECT * 全字段查询</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 问题：没有 Entity View → SELECT * 全字段查询</span><br/>List&lt;Order&gt; orders = em.createQuery(<br/>    \"SELECT o FROM Order o\", Order.class)<br/>    .getResultList();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// SQL: SELECT o.id, o.status, o.customer_id, o.total_amount,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      o.shipping_address, o.billing_address, o.notes,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      o.created_at, o.updated_at, o.deleted, o.version,</span><br/><span style=\"color:#6c7086;font-style:italic;\">//      o.discount_code, o.tax_amount, o.currency, o.source</span><br/><span style=\"color:#6c7086;font-style:italic;\">// → 查询了 15+ 列，但只用到 3 列！</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决：Entity View 精确投影</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 解决：Entity View 精确投影</span><br/>@EntityView(Order.class)<br/>public interface OrderListView {<br/>    @IdMapping Long getId();<br/>    String getStatus();<br/>    @Mapping(\"customer.name\") String getCustomerName();<br/>}<br/><br/>CriteriaBuilder&lt;OrderListView&gt; cb = evm.applySetting(<br/>    EntityViewSetting.create(OrderListView.class),<br/>    cbf.create(em, Order.class));<br/>List&lt;OrderListView&gt; views = cb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（只查询 3 列 + 自动 JOIN）:<br/>SELECT o.id, o.status, c.name<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>-- → 只查询 3 列 ✅<br/>-- → 数据库可以使用 (id, status) 覆盖索引<br/>-- → 网络传输数据量减少 80%+</p></section>\n\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n指标SELECT * (传统 JPA)Entity View (精确投影)提升\n\n\n查询列数15+380% 减少\n单行传输数据~500 bytes~60 bytes88% 减少\n覆盖索引命中不可能可能Index-Only Scan\nEntityManager 托管是（快照 + 脏检查）否（只读代理）GC 压力大幅降低\n一级缓存占用高零无缓存溢出风险\n\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">进阶：多层级 Entity View 仍精确投影</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>public interface OrderDetailView {<br/>    @IdMapping Long getId();<br/>    String getStatus();<br/>    BigDecimal getTotalAmount();<br/>    @Mapping(\"customer\") CustomerBriefView getCustomer();<br/>    @Mapping(\"items\") Set&lt;OrderItemBriefView&gt; getItems();<br/>}<br/><br/>@EntityView(Customer.class)<br/>public interface CustomerBriefView {<br/>    @IdMapping Long getId();<br/>    String getName();<br/>    String getEmail();<br/>}<br/><br/>@EntityView(OrderItem.class)<br/>public interface OrderItemBriefView {<br/>    @IdMapping Long getId();<br/>    String getProductName();<br/>    Integer getQuantity();<br/>    BigDecimal getUnitPrice();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 即使嵌套 3 层 View，仍只查询需要的列:<br/>SELECT o.id, o.status, o.total_amount,<br/>       c.id, c.name, c.email,<br/>       i.id, i.product_name, i.quantity, i.unit_price<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>LEFT JOIN order_items i ON i.order_id = o.id<br/>-- 每层 View 只投影声明的字段<br/>-- 不会加载 customer.address、customer.phone 等未映射字段</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.2 N+1 问题检测与解决</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">N+1 问题是 ORM 最经典的性能杀手——查询 1 次获取 N 个父实体，再逐条查询 N 次获取子集合。在 Entity View 中，当 Subview 集合使用默认 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT</code> 获取策略时也会触发。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-3 N+1 问题发生机制</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">应用代码</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">Blaze-Persistence</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">数据库</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 ... 重复 98 次 ...</p><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 总计: 1 + 100 = 101 条 SQL！</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">问题代码：默认 SELECT 策略</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ N+1: Subview 默认 SELECT 策略</span><br/>@EntityView(Order.class)<br/>public interface OrderWithItems {<br/>    @IdMapping Long getId();<br/>    String getStatus();<br/>    Set&lt;OrderItemView&gt; getItems(); <span style=\"color:#6c7086;font-style:italic;\">// 每个 Order 触发一次子查询!</span><br/>}<br/><br/>@EntityView(OrderItem.class)<br/>public interface OrderItemView {<br/>    @IdMapping Long getId();<br/>    String getProductName();<br/>    Integer getQuantity();<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 查询 100 个订单:</span><br/>List&lt;OrderWithItems&gt; orders = evm.applySetting(<br/>    EntityViewSetting.create(OrderWithItems.class),<br/>    cbf.create(em, Order.class))<br/>    .getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（N+1 问题）:<br/>-- 第 1 条: 查询所有 Order<br/>SELECT o.id, o.status FROM orders o<br/><br/>-- 第 2 ~ 101 条: 每个 Order 逐条查询 items<br/>SELECT i.id, i.product_name, i.quantity FROM order_items i WHERE i.order_id = 1<br/>SELECT i.id, i.product_name, i.quantity FROM order_items i WHERE i.order_id = 2<br/>SELECT i.id, i.product_name, i.quantity FROM order_items i WHERE i.order_id = 3<br/>...<br/>SELECT i.id, i.product_name, i.quantity FROM order_items i WHERE i.order_id = 100<br/>-- 总计: 101 条 SQL</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决方案 1：@BatchFetch 批量加载</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 解决1: @BatchFetch 批量加载</span><br/>@EntityView(Order.class)<br/>public interface OrderWithItemsBatched {<br/>    @IdMapping Long getId();<br/>    String getStatus();<br/><br/>    @BatchFetch(size = 50)<br/>    Set&lt;OrderItemView&gt; getItems();<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 将 100 个 order_id 分为 2 批，用 IN (...) 批量加载</span><br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（@BatchFetch 优化后）:<br/>-- 第 1 条: 查询所有 Order<br/>SELECT o.id, o.status FROM orders o<br/><br/>-- 第 2 条: 批量加载前 50 个 Order 的 items<br/>SELECT i.id, i.product_name, i.quantity, i.order_id<br/>FROM order_items i<br/>WHERE i.order_id IN (1, 2, 3, ..., 50)<br/><br/>-- 第 3 条: 批量加载后 50 个 Order 的 items<br/>SELECT i.id, i.product_name, i.quantity, i.order_id<br/>FROM order_items i<br/>WHERE i.order_id IN (51, 52, 53, ..., 100)<br/><br/>-- 总计: 1 + 2 = 3 条 SQL（从 101 条降到 3 条）</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决方案 2：Correlated Subquery</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 解决2: @MappingCorrelated 子查询关联</span><br/>@EntityView(Order.class)<br/>public interface OrderWithItemsCorrelated {<br/>    @IdMapping Long getId();<br/>    String getStatus();<br/><br/>    @MappingCorrelated(<br/>        correlator = OrderItemCorrelator.class,<br/>        correlationBasis = \"id\",<br/>        correlationResult = \"this\",<br/>        fetch = FetchStrategy.SUBSELECT<br/>    )<br/>    Set&lt;OrderItemView&gt; getItems();<br/>}<br/><br/>public class OrderItemCorrelator implements CorrelationProvider {<br/>    @Override<br/>    public void applyCorrelation(<br/>            CorrelationBuilder correlationBuilder, String correlationExpression) {<br/>        correlationBuilder<br/>            .correlate(OrderItem.class, \"i\")<br/>            .on(\"i.order.id\").eqExpression(correlationExpression)<br/>            .end();<br/>    }<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（Correlated Subquery — SUBSELECT 策略）:<br/>-- 第 1 条: 查询所有 Order<br/>SELECT o.id, o.status FROM orders o<br/><br/>-- 第 2 条: 一次性子查询加载所有 items<br/>SELECT i.id, i.product_name, i.quantity, i.order_id<br/>FROM order_items i<br/>WHERE i.order_id IN (<br/>    SELECT o.id FROM orders o<br/>)<br/>-- 总计: 2 条 SQL（无论有多少 Order）</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决方案 3：JOIN 获取（单查询）</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 解决3: JOIN 获取 — 单条 SQL 搞定</span><br/>@EntityView(Order.class)<br/>public interface OrderWithItemsJoined {<br/>    @IdMapping Long getId();<br/>    String getStatus();<br/><br/>    @MappingCorrelated(<br/>        correlator = OrderItemCorrelator.class,<br/>        correlationBasis = \"id\",<br/>        correlationResult = \"this\",<br/>        fetch = FetchStrategy.JOIN<br/>    )<br/>    Set&lt;OrderItemView&gt; getItems();<br/>}</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（JOIN — 单条查询）:<br/>SELECT o.id, o.status,<br/>       i.id AS items_id,<br/>       i.product_name AS items_productName,<br/>       i.quantity AS items_quantity<br/>FROM orders o<br/>LEFT JOIN order_items i ON i.order_id = o.id<br/>-- 总计: 1 条 SQL<br/>-- 注意: JOIN 会产生笛卡尔积，行数 = Order数 × 平均Items数</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-4 N+1 解决方案对比</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">size</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">50</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">N+1 问题<br/>100 Orders → 101 条 SQL\"] --> S1[\"@BatchFetch<br/>size=50</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@BatchFetch<br/>size=50</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">Correlated Subquery<br/>SUBSELECT</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">JOIN 获取<br/>单条 SQL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">3 条 SQL<br/>IN (...) 批量<br/>✅ 简单配置<br/>⚠️ 仍有多条 SQL</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">2 条 SQL<br/>子查询一次性<br/>✅ 行数不膨胀<br/>⚠️ 子查询性能</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">1 条 SQL<br/>LEFT JOIN<br/>✅ 最少 SQL<br/>⚠️ 笛卡尔积膨胀</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">推荐选择</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">子集合小 → JOIN<br/>子集合大 → SUBSELECT<br/>快速修复 → @BatchFetch</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n方案SQL 条数行数膨胀配置难度适用场景\n\n\n<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@BatchFetch(size=50)</code>1 + ⌈N/size⌉无一行注解快速修复、通用场景\nCorrelated SUBSELECT2无需要 CorrelationProvider子集合数据量大\nJOIN 获取1有（笛卡尔积）需要 CorrelationProvider子集合小、需要排序\n\n\n</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.3 分页优化 — Offset vs Keyset</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">OFFSET 分页是最常见的分页方式，但在深翻页场景下性能急剧恶化——第 5000 页意味着数据库要扫描 100000 行然后丢弃前 99980 行。Keyset 分页通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE</code> 条件代替 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET</code>，实现恒定 O(1) 的分页性能。</p></section>\n\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">问题：OFFSET 深翻页</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ OFFSET 分页 — 第 5000 页性能极差</span><br/>PaginatedCriteriaBuilder&lt;OrderView&gt; pcb = evm.applySetting(<br/>    EntityViewSetting.create(OrderView.class, 99980, 20),<br/>    cbf.create(em, Order.class)<br/>        .orderByAsc(\"id\")<br/>);<br/>PagedList&lt;OrderView&gt; page = pcb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- OFFSET 分页生成的 SQL:<br/>SELECT o.id, o.status, o.total_amount<br/>FROM orders o<br/>ORDER BY o.id ASC<br/>LIMIT 20 OFFSET 99980<br/>-- → 扫描 100,000 行，丢弃 99,980 行<br/>-- → 页码越大越慢，第 5000 页比第 1 页慢 500 倍</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决：Keyset 分页 — 恒定性能</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ Keyset 分页 — 恒定性能</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 第一页（无 keyset，等价于普通 LIMIT）:</span><br/>PaginatedCriteriaBuilder&lt;OrderView&gt; firstPage = evm.applySetting(<br/>    EntityViewSetting.create(OrderView.class, 0, 20),<br/>    cbf.create(em, Order.class)<br/>        .orderByAsc(\"id\")<br/>);<br/>PagedList&lt;OrderView&gt; page1 = firstPage.getResultList();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 后续页（使用前一页的 KeysetPage）:</span><br/>KeysetPage keyset = page1.getKeysetPage();<br/>PaginatedCriteriaBuilder&lt;OrderView&gt; nextPage = evm.applySetting(<br/>    EntityViewSetting.create(OrderView.class, keyset, 20),<br/>    cbf.create(em, Order.class)<br/>        .orderByAsc(\"id\")<br/>);<br/>PagedList&lt;OrderView&gt; page2 = nextPage.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- Keyset 分页生成的 SQL:<br/>-- 第一页:<br/>SELECT o.id, o.status, o.total_amount<br/>FROM orders o<br/>ORDER BY o.id ASC<br/>LIMIT 20<br/><br/>-- 第二页（使用 Keyset）:<br/>SELECT o.id, o.status, o.total_amount<br/>FROM orders o<br/>WHERE o.id &gt; 12345       -- 上一页最后一条的 id<br/>ORDER BY o.id ASC<br/>LIMIT 20<br/>-- → Index Seek, 只扫描 20 行 ✅<br/>-- → 无论第几页，性能恒定 O(1)</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">进阶：复合排序键的 Keyset 分页</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 复合排序键: createdAt DESC, id DESC</span><br/>PaginatedCriteriaBuilder&lt;OrderView&gt; pcb = evm.applySetting(<br/>    EntityViewSetting.create(OrderView.class, keyset, 20),<br/>    cbf.create(em, Order.class)<br/>        .orderByDesc(\"createdAt\")<br/>        .orderByDesc(\"id\")<br/>);<br/>PagedList&lt;OrderView&gt; page = pcb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 复合 Keyset 生成的 SQL:<br/>SELECT o.id, o.status, o.total_amount, o.created_at<br/>FROM orders o<br/>WHERE (o.created_at, o.id) &lt; (?, ?)<br/>ORDER BY o.created_at DESC, o.id DESC<br/>LIMIT 20<br/>-- 参数: [lastCreatedAt, lastId]<br/>-- → 行值比较 (row value comparison) 利用复合索引<br/>-- → 推荐创建索引: CREATE INDEX idx_order_created_id<br/>--   ON orders(created_at DESC, id DESC)</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n指标OFFSET 分页Keyset 分页\n\n\n第 1 页 (20条)~5ms~5ms\n第 100 页 (20条)~50ms~5ms\n第 5000 页 (20条)~2500ms~5ms\n可跳页✅❌ 只能上一页/下一页\n数据一致性⚠️ 插入导致漂移✅ 无漂移\n需要稳定排序推荐必须（含唯一列）\n\n\n</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.4 CTE 优化复杂查询</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">当报表查询涉及聚合 + 排名 + 过滤时，嵌套子查询会让 SQL 难以阅读和优化。CTE 将复杂逻辑分解为命名步骤，既提高可读性，又让数据库优化器有更大的优化空间。</p></section>\n\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">实战：月度客户销售排名 Top 10</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// CTE 实体定义</span><br/>@CTE<br/>@Entity<br/>public class MonthlySalesCTE {<br/>    @Id Long customerId;<br/>    String customerName;<br/>    BigDecimal monthlyTotal;<br/>    Integer salesRank;<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 构建查询</span><br/>LocalDate startOfMonth = LocalDate.of(2026, 4, 1);<br/>LocalDate endOfMonth = LocalDate.of(2026, 5, 1);<br/><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .with(MonthlySalesCTE.class)<br/>        .from(Order.class, \"o\")<br/>        .bind(\"customerId\").select(\"o.customer.id\")<br/>        .bind(\"customerName\").select(\"o.customer.name\")<br/>        .bind(\"monthlyTotal\").select(\"SUM(o.totalAmount)\")<br/>        .bind(\"salesRank\").select(<br/>            \"WINDOW_ROW_NUMBER() OVER (ORDER BY SUM(o.totalAmount) DESC)\")<br/>        .where(\"o.createdAt\").ge(startOfMonth)<br/>        .where(\"o.createdAt\").lt(endOfMonth)<br/>        .groupBy(\"o.customer.id\")<br/>        .groupBy(\"o.customer.name\")<br/>    .end()<br/>    .from(MonthlySalesCTE.class, \"m\")<br/>    .select(\"m.salesRank\")<br/>    .select(\"m.customerName\")<br/>    .select(\"m.monthlyTotal\")<br/>    .where(\"m.salesRank\").le(10)<br/>    .orderByAsc(\"m.salesRank\");</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>WITH MonthlySalesCTE(customerId, customerName, monthlyTotal, salesRank) AS (<br/>    SELECT c.id,<br/>           c.name,<br/>           SUM(o.total_amount),<br/>           ROW_NUMBER() OVER (ORDER BY SUM(o.total_amount) DESC)<br/>    FROM orders o<br/>    JOIN customers c ON o.customer_id = c.id<br/>    WHERE o.created_at &gt;= '2026-04-01'<br/>      AND o.created_at &lt; '2026-05-01'<br/>    GROUP BY c.id, c.name<br/>)<br/>SELECT m.salesRank, m.customerName, m.monthlyTotal<br/>FROM MonthlySalesCTE m<br/>WHERE m.salesRank &lt;= 10<br/>ORDER BY m.salesRank ASC<br/><br/>-- 执行计划优势:<br/>-- 1. CTE 物化一次，主查询只扫描 ≤10 行<br/>-- 2. GROUP BY + SUM 在 CTE 内完成，窗口函数紧随其后<br/>-- 3. 外层过滤 salesRank &lt;= 10 极快（只过滤聚合结果）</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff44;border-radius:8px;padding:14px 16px;margin:14px 0 20px;font-size:14px;line-height:1.8;color:#2b2b2b;\">\n<strong style=\"color:#1a1a2e;font-weight:700;\">为什么不用嵌套子查询？</strong>嵌套方案需要 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT * FROM (SELECT * FROM (SELECT ... GROUP BY) t1) t2 WHERE rank <= 10</code>——三层嵌套。CTE 版本将每步拆为独立命名块，SQL 可读性提升且方便调试（可以单独执行 CTE 部分验证中间结果）。\n</section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.5 批量 DML 优化</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">逐条 DML 是生产环境最常见的性能反模式——N 条记录产生 N 条 SQL 语句，每条都有网络往返、事务日志写入、索引更新的开销。Blaze-Persistence 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">CriteriaBuilder</code> 支持批量 UPDATE、DELETE 和 INSERT...SELECT，将 N 条语句合并为 1 条。</p></section>\n\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">问题：逐条更新</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 逐条更新 — N 条 UPDATE</span><br/>List&lt;Order&gt; expiredOrders = em.createQuery(<br/>    \"SELECT o FROM Order o WHERE o.status = :s AND o.createdAt &lt; :cutoff\",<br/>    Order.class)<br/>    .setParameter(\"s\", OrderStatus.PENDING)<br/>    .setParameter(\"cutoff\", cutoffDate)<br/>    .getResultList();<br/><br/>for (Order o : expiredOrders) {<br/>    o.setStatus(OrderStatus.CANCELLED);<br/>    o.setUpdatedAt(Instant.now());<br/>    em.merge(o);<br/>}<br/><span style=\"color:#6c7086;font-style:italic;\">// → 先 SELECT 加载所有实体，再逐条 UPDATE</span><br/><span style=\"color:#6c7086;font-style:italic;\">// → 1000 条过期订单 = 1 SELECT + 1000 UPDATE = 1001 条 SQL</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决 1：批量 UPDATE</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 批量 UPDATE — 1 条 SQL 更新所有匹配行</span><br/>int updated = cbf.update(em, Order.class, \"o\")<br/>    .set(\"o.status\", OrderStatus.CANCELLED)<br/>    .set(\"o.updatedAt\", Instant.now())<br/>    .where(\"o.status\").eq(OrderStatus.PENDING)<br/>    .where(\"o.createdAt\").lt(cutoffDate)<br/>    .executeUpdate();<br/><br/>System.out.println(\"已取消 \" + updated + \" 个过期订单\");</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL（1 条搞定）:<br/>UPDATE orders<br/>SET status = 'CANCELLED',<br/>    updated_at = '2026-04-21T10:30:00Z'<br/>WHERE status = 'PENDING'<br/>  AND created_at &lt; '2026-04-01T00:00:00Z'<br/>-- → 1 条 SQL 更新 1000 行<br/>-- → 无需先 SELECT 加载实体到内存</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决 2：批量 DELETE</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ 批量 DELETE — 清理一年前的审计日志</span><br/>Instant oneYearAgo = Instant.now().minus(365, ChronoUnit.DAYS);<br/><br/>int deleted = cbf.delete(em, AuditLog.class, \"a\")<br/>    .where(\"a.createdAt\").lt(oneYearAgo)<br/>    .executeUpdate();<br/><br/>System.out.println(\"已清理 \" + deleted + \" 条过期审计日志\");</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>DELETE FROM audit_logs<br/>WHERE created_at &lt; '2025-04-21T10:30:00Z'<br/>-- → 单条 SQL 批量删除</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">解决 3：INSERT...SELECT（数据归档）</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ INSERT...SELECT — 将旧订单归档到 order_archive 表</span><br/>int archived = cbf.insert(em, OrderArchive.class)<br/>    .from(Order.class, \"o\")<br/>    .bind(\"id\").select(\"o.id\")<br/>    .bind(\"status\").select(\"o.status\")<br/>    .bind(\"customerName\").select(\"o.customer.name\")<br/>    .bind(\"totalAmount\").select(\"o.totalAmount\")<br/>    .bind(\"createdAt\").select(\"o.createdAt\")<br/>    .bind(\"archivedAt\").select(\"CURRENT_TIMESTAMP\")<br/>    .where(\"o.createdAt\").lt(archiveDate)<br/>    .where(\"o.status\").in(OrderStatus.COMPLETED, OrderStatus.CANCELLED)<br/>    .executeUpdate();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 归档后删除原表数据:</span><br/>int cleaned = cbf.delete(em, Order.class, \"o\")<br/>    .where(\"o.createdAt\").lt(archiveDate)<br/>    .where(\"o.status\").in(OrderStatus.COMPLETED, OrderStatus.CANCELLED)<br/>    .executeUpdate();<br/><br/>System.out.println(\"已归档 \" + archived + \" 条，清理 \" + cleaned + \" 条\");</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL — INSERT...SELECT:<br/>INSERT INTO order_archive(id, status, customer_name,<br/>                          total_amount, created_at, archived_at)<br/>SELECT o.id, o.status, c.name,<br/>       o.total_amount, o.created_at, CURRENT_TIMESTAMP<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>WHERE o.created_at &lt; '2025-04-01'<br/>  AND o.status IN ('COMPLETED', 'CANCELLED')<br/><br/>-- 随后执行的 DELETE:<br/>DELETE FROM orders<br/>WHERE created_at &lt; '2025-04-01'<br/>  AND status IN ('COMPLETED', 'CANCELLED')<br/><br/>-- → 数据在数据库内部移动，不经过应用层<br/>-- → 比加载到内存再逐条插入快 100x+</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n操作逐条方式批量方式加速比 (1000行)\n\n\nUPDATE1 SELECT + 1000 UPDATE1 UPDATE~300x\nDELETE1 SELECT + 1000 DELETE1 DELETE~300x\nINSERT...SELECTSELECT + 1000 INSERT1 INSERT...SELECT~500x\n\n\n</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.6 报表查询（窗口函数 + 聚合）</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">报表场景通常需要在同一查询中同时计算聚合值（SUM、AVG）和窗口函数（累计、排名、移动平均）。Blaze-Persistence 的窗口函数支持让这些计算在单条 SQL 中完成，避免多次查询。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-8 报表查询架构：聚合 + 窗口函数联合</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">原始订单数据<br/>orders 表\"] --> AGG[\"第 1 步: GROUP BY 聚合<br/>按日/周/月分组</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 1 步: GROUP BY 聚合<br/>按日/周/月分组</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">第 2 步: 窗口函数<br/>在聚合结果上计算</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">ROW_NUMBER<br/>排名</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SUM OVER<br/>累计求和</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">AVG OVER ROWS<br/>移动平均</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">LAG / LEAD<br/>同比/环比</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">最终报表<br/>单条 SQL 返回所有维度</p></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">实战：每日销售额 + 7 日移动平均 + 累计总额</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 每日销售报表：日销售额 + 7日移动平均 + 累计总额</span><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .from(Order.class, \"o\")<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 日期维度</span><br/>    .select(\"FUNCTION('DATE_TRUNC', 'day', o.createdAt)\")<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 日销售额</span><br/>    .select(\"SUM(o.totalAmount)\")<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 7日移动平均</span><br/>    .select(\"WINDOW_AVG(SUM(o.totalAmount)) OVER (\"<br/>        + \"ORDER BY FUNCTION('DATE_TRUNC', 'day', o.createdAt) \"<br/>        + \"ROWS BETWEEN 6 PRECEDING AND CURRENT ROW)\")<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 累计总额</span><br/>    .select(\"WINDOW_SUM(SUM(o.totalAmount)) OVER (\"<br/>        + \"ORDER BY FUNCTION('DATE_TRUNC', 'day', o.createdAt) \"<br/>        + \"ROWS UNBOUNDED PRECEDING)\")<br/>    <span style=\"color:#6c7086;font-style:italic;\">// 日环比（前一天销售额）</span><br/>    .select(\"WINDOW_LAG(SUM(o.totalAmount), 1) OVER (\"<br/>        + \"ORDER BY FUNCTION('DATE_TRUNC', 'day', o.createdAt))\")<br/>    .where(\"o.createdAt\").ge(startDate)<br/>    .where(\"o.createdAt\").lt(endDate)<br/>    .groupBy(\"FUNCTION('DATE_TRUNC', 'day', o.createdAt)\")<br/>    .orderByAsc(\"FUNCTION('DATE_TRUNC', 'day', o.createdAt)\");<br/><br/>List&lt;Tuple&gt; report = cb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 PostgreSQL SQL:<br/>SELECT DATE_TRUNC('day', o.created_at) AS sale_date,<br/>       SUM(o.total_amount) AS daily_total,<br/>       AVG(SUM(o.total_amount)) OVER (<br/>           ORDER BY DATE_TRUNC('day', o.created_at)<br/>           ROWS BETWEEN 6 PRECEDING AND CURRENT ROW<br/>       ) AS moving_avg_7d,<br/>       SUM(SUM(o.total_amount)) OVER (<br/>           ORDER BY DATE_TRUNC('day', o.created_at)<br/>           ROWS UNBOUNDED PRECEDING<br/>       ) AS cumulative_total,<br/>       LAG(SUM(o.total_amount), 1) OVER (<br/>           ORDER BY DATE_TRUNC('day', o.created_at)<br/>       ) AS prev_day_total<br/>FROM orders o<br/>WHERE o.created_at &gt;= '2026-04-01'<br/>  AND o.created_at &lt; '2026-05-01'<br/>GROUP BY DATE_TRUNC('day', o.created_at)<br/>ORDER BY DATE_TRUNC('day', o.created_at) ASC<br/><br/>-- 单条 SQL 返回 5 个维度:<br/>-- | sale_date  | daily_total | moving_avg_7d | cumulative | prev_day |<br/>-- |------------|-------------|---------------|------------|----------|<br/>-- | 2026-04-01 |    12500.00 |      12500.00 |   12500.00 |     NULL |<br/>-- | 2026-04-02 |     8300.00 |      10400.00 |   20800.00 | 12500.00 |<br/>-- | 2026-04-03 |    15200.00 |      12000.00 |   36000.00 |  8300.00 |<br/>-- | ...        |         ... |           ... |        ... |      ... |</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.7 软删除 + ViewFilter</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">软删除是企业应用的标配——删除操作只设 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">deleted = true</code>，不真正删除数据。问题在于每条查询都要加 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE deleted = false</code>，极易遗漏。<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@ViewFilter</code> 把这个条件抽为命名过滤器，一次定义、全局复用。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-9 软删除 + 多租户 ViewFilter 透明注入管线</p><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">DEFINE</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@ViewFilter(name='activeOnly',<br/>value='deleted = false')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">@ViewFilter(name='currentTenant',<br/>value='tenantId = :tenantId')</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">ACTIVATE</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">EntityViewSetting.create()</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.addViewFilter('activeOnly')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.addViewFilter('currentTenant')</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">.addOptionalParameter(<br/>'tenantId', currentTenantId)</p></section></section><section style=\"border:2px solid #1e6fff55;border-radius:10px;padding:14px 12px;margin:6px 0;background:#f5f5f5;\"><p style=\"font-size:12px;font-weight:700;color:#1e6fff;margin:0 0 8px;\">MERGE</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT o FROM Order o</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">AND o.deleted = false</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">AND o.tenantId = :tenantId</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">SELECT o FROM Order o<br/>WHERE o.deleted = false<br/>AND o.tenantId = :tenantId</p></section></section></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Step 1：定义带过滤器的 Entity View</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@EntityView(Order.class)<br/>@ViewFilter(name = \"activeOnly\", value = \"deleted = false\")<br/>@ViewFilter(name = \"currentTenant\", value = \"tenantId = :tenantId\")<br/>public interface OrderView {<br/>    @IdMapping Long getId();<br/>    String getStatus();<br/>    BigDecimal getTotalAmount();<br/>    @Mapping(\"customer.name\") String getCustomerName();<br/>    Instant getCreatedAt();<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Step 2：查询时激活过滤器</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 方式 1: 手动激活过滤器</span><br/>EntityViewSetting&lt;OrderView, CriteriaBuilder&lt;OrderView&gt;&gt; setting =<br/>    EntityViewSetting.create(OrderView.class);<br/>setting.addViewFilter(\"activeOnly\");<br/>setting.addViewFilter(\"currentTenant\");<br/>setting.addOptionalParameter(\"tenantId\", TenantContext.current());<br/><br/>CriteriaBuilder&lt;OrderView&gt; cb = evm.applySetting(setting,<br/>    cbf.create(em, Order.class)<br/>        .where(\"status\").eq(OrderStatus.CONFIRMED)<br/>        .orderByDesc(\"createdAt\"));<br/><br/>List&lt;OrderView&gt; orders = cb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 JPQL（过滤器自动追加到 WHERE）:<br/>SELECT o FROM Order o<br/>WHERE o.status = :param_0<br/>  AND o.deleted = false<br/>  AND o.tenantId = :tenantId<br/>ORDER BY o.createdAt DESC<br/><br/>-- PostgreSQL 原生 SQL:<br/>SELECT o.id, o.status, o.total_amount, c.name, o.created_at<br/>FROM orders o<br/>JOIN customers c ON o.customer_id = c.id<br/>WHERE o.status = 'CONFIRMED'<br/>  AND o.deleted = false<br/>  AND o.tenant_id = 'tenant-abc-123'<br/>ORDER BY o.created_at DESC<br/>-- → 软删除 + 多租户条件自动注入<br/>-- → 业务代码无需手动追加这些条件</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">进阶：ViewFilterProvider 自动注入参数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ViewFilterProvider: 参数由 Provider 自动提供，无需手动设置</span><br/>@Component<br/>public class TenantViewFilterProvider implements ViewFilterProvider {<br/><br/>    @Override<br/>    public String getFilterName() {<br/>        return \"currentTenant\";<br/>    }<br/><br/>    @Override<br/>    public Map&lt;String, Object&gt; getFilterParameters() {<br/>        return Map.of(\"tenantId\", TenantContext.current());<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// Spring 拦截器自动激活过滤器:</span><br/>@Component<br/>public class TenantFilterInterceptor implements HandlerInterceptor {<br/><br/>    @Override<br/>    public boolean preHandle(HttpServletRequest request,<br/>            HttpServletResponse response, Object handler) {<br/>        String tenantId = request.getHeader(\"X-Tenant-Id\");<br/>        TenantContext.set(tenantId);<br/>        return true;<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 控制器中无需关心租户过滤——完全透明:</span><br/>@GetMapping(\"/orders\")<br/>public List&lt;OrderView&gt; listOrders() {<br/>    EntityViewSetting&lt;OrderView, CriteriaBuilder&lt;OrderView&gt;&gt; setting =<br/>        EntityViewSetting.create(OrderView.class);<br/>    <span style=\"color:#6c7086;font-style:italic;\">// ViewFilterProvider 自动注入 tenantId</span><br/>    return evm.applySetting(setting,<br/>        cbf.create(em, Order.class)).getResultList();<br/>}</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.8 全文搜索集成</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">关系型数据库（如 PostgreSQL）内建的全文搜索功能已经非常强大，但 JPA/JPQL 不原生支持 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">tsvector</code> / <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">tsquery</code> 语法。通过 <span style=\"color:#1e6fff;\">第 20 章</span> 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 扩展点，我们可以把数据库级全文搜索无缝集成到 Blaze-Persistence。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-10 全文搜索函数注册与 SQL 渲染流程</p><table style=\"width:100%;border-collapse:collapse;margin:0 0 8px;\"><tr><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">开发者</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilder[BR]Configuration</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">CriteriaBuilder</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">FunctionRenderer</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">PgSearchFunction</th><th style=\"background:#f5f5f5;padding:6px 10px;font-size:12px;font-weight:700;color:#1e6fff;border:1px solid #d0d7de;text-align:center;\">SQL Buffer</th></tr></table><p style=\"text-align:center;font-size:11px;color:#888;background:#f5f5f5;border:1px solid #e6a81744;border-radius:4px;padding:4px 8px;margin:3px auto;max-width:80%;\">📌 启动时注册一次</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Step 1：注册自定义全文搜索函数</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">public class PgSearchFunction implements JpqlFunction {<br/><br/>    @Override<br/>    public boolean hasArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public boolean hasParenthesesIfNoArguments() {<br/>        return true;<br/>    }<br/><br/>    @Override<br/>    public Class&lt;?&gt; getReturnType(Class&lt;?&gt; firstArgumentType) {<br/>        return Boolean.class;<br/>    }<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\"to_tsvector('chinese', \");<br/>        ctx.addArgument(0);   <span style=\"color:#6c7086;font-style:italic;\">// 被搜索的字段</span><br/>        ctx.addChunk(\") @@ to_tsquery('chinese', \");<br/>        ctx.addArgument(1);   <span style=\"color:#6c7086;font-style:italic;\">// 搜索关键词</span><br/>        ctx.addChunk(\")\");<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 搜索排名函数</span><br/>public class PgTsRankFunction implements JpqlFunction {<br/><br/>    @Override<br/>    public boolean hasArguments() { return true; }<br/><br/>    @Override<br/>    public boolean hasParenthesesIfNoArguments() { return true; }<br/><br/>    @Override<br/>    public Class&lt;?&gt; getReturnType(Class&lt;?&gt; firstArgumentType) {<br/>        return Float.class;<br/>    }<br/><br/>    @Override<br/>    public void render(FunctionRenderContext ctx) {<br/>        ctx.addChunk(\"ts_rank(to_tsvector('chinese', \");<br/>        ctx.addArgument(0);<br/>        ctx.addChunk(\"), to_tsquery('chinese', \");<br/>        ctx.addArgument(1);<br/>        ctx.addChunk(\"))\");<br/>    }<br/>}<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// 注册</span><br/>CriteriaBuilderConfiguration config = Criteria.getDefault();<br/>config.registerFunction(<br/>    new JpqlFunctionGroup(\"pg_search\", new PgSearchFunction()));<br/>config.registerFunction(<br/>    new JpqlFunctionGroup(\"pg_ts_rank\", new PgTsRankFunction()));</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Step 2：在查询中使用全文搜索</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 全文搜索文章 + 按相关度排序</span><br/>String searchKeyword = \"Blaze-Persistence &amp; 优化\";<br/><br/>CriteriaBuilder&lt;ArticleSearchView&gt; cb = evm.applySetting(<br/>    EntityViewSetting.create(ArticleSearchView.class),<br/>    cbf.create(em, Article.class, \"a\")<br/>        .where(\"FUNCTION('pg_search', a.content, :keyword)\").eq(true)<br/>        .orderByDesc(\"FUNCTION('pg_ts_rank', a.content, :keyword)\")<br/>);<br/>cb.setParameter(\"keyword\", searchKeyword);<br/><br/>List&lt;ArticleSearchView&gt; results = cb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 PostgreSQL SQL:<br/>SELECT a.id, a.title, a.author, a.created_at<br/>FROM articles a<br/>WHERE to_tsvector('chinese', a.content)<br/>      @@ to_tsquery('chinese', 'Blaze-Persistence &amp; 优化')<br/>ORDER BY ts_rank(<br/>    to_tsvector('chinese', a.content),<br/>    to_tsquery('chinese', 'Blaze-Persistence &amp; 优化')<br/>) DESC<br/><br/>-- 配合 GIN 索引性能极佳:<br/>-- CREATE INDEX idx_article_content_fts<br/>--   ON articles USING GIN (to_tsvector('chinese', content));</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.9 递归 CTE（树形结构）</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">组织架构、分类目录、评论回复——这些都是典型的树形结构。传统方式需要递归查询（应用层 N 次 SQL）或邻接表方案。递归 CTE 可以在单条 SQL 中展开任意深度的树。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-11 递归 CTE 树展开过程</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\nAnchor — level=0\nCEO<br/>path=/CEO\n\n→\n\nRecursive 第 1 轮 — level=1\nVP-Engineering<br/>VP-Sales · VP-Finance\n\n→\n\nRecursive 第 2 轮 — level=2\nBackend Team · Frontend Team<br/>APAC Sales · EMEA Sales\n\n→\n\nRecursive 第 3 轮 — level=3\nJava Squad · Go Squad<br/>React Squad\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">CTE 实体定义</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">@CTE<br/>@Entity<br/>public class OrgTreeCTE {<br/>    @Id Long id;<br/>    String name;<br/>    Long parentId;<br/>    Integer level;<br/>    String path;<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">构建递归查询</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .withRecursive(OrgTreeCTE.class)<br/>        <span style=\"color:#6c7086;font-style:italic;\">// ====== Anchor: 根节点（parent IS NULL）======</span><br/>        .from(Department.class, \"d\")<br/>        .bind(\"id\").select(\"d.id\")<br/>        .bind(\"name\").select(\"d.name\")<br/>        .bind(\"parentId\").select(\"d.parent.id\")<br/>        .bind(\"level\").select(\"0\")<br/>        .bind(\"path\").select(\"CONCAT('/', d.name)\")<br/>        .where(\"d.parent\").isNull()<br/>    .unionAll()<br/>        <span style=\"color:#6c7086;font-style:italic;\">// ====== Recursive: 子节点关联父节点 ======</span><br/>        .from(Department.class, \"d\")<br/>        .from(OrgTreeCTE.class, \"t\")<br/>        .bind(\"id\").select(\"d.id\")<br/>        .bind(\"name\").select(\"d.name\")<br/>        .bind(\"parentId\").select(\"d.parent.id\")<br/>        .bind(\"level\").select(\"t.level + 1\")<br/>        .bind(\"path\").select(\"CONCAT(t.path, '/', d.name)\")<br/>        .where(\"d.parent.id\").eqExpression(\"t.id\")<br/>    .end()<br/>    <span style=\"color:#6c7086;font-style:italic;\">// ====== 主查询: 从 CTE 读取完整树 ======</span><br/>    .from(OrgTreeCTE.class, \"t\")<br/>    .select(\"t.level\")<br/>    .select(\"t.name\")<br/>    .select(\"t.path\")<br/>    .select(\"t.parentId\")<br/>    .orderByAsc(\"t.path\");<br/><br/>List&lt;Tuple&gt; tree = cb.getResultList();</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 生成的 SQL:<br/>WITH RECURSIVE OrgTreeCTE(id, name, parentId, level, path) AS (<br/>    -- Anchor: 根节点<br/>    SELECT d.id, d.name, d.parent_id, 0,<br/>           CONCAT('/', d.name)<br/>    FROM departments d<br/>    WHERE d.parent_id IS NULL<br/><br/>    UNION ALL<br/><br/>    -- Recursive: 逐层展开子节点<br/>    SELECT d.id, d.name, d.parent_id, t.level + 1,<br/>           CONCAT(t.path, '/', d.name)<br/>    FROM departments d<br/>    JOIN OrgTreeCTE t ON d.parent_id = t.id<br/>)<br/>SELECT t.level, t.name, t.path, t.parentId<br/>FROM OrgTreeCTE t<br/>ORDER BY t.path ASC<br/><br/>-- 查询结果（按 path 排序 → 天然树形缩进）:<br/>-- | level | name         | path                             |<br/>-- |-------|--------------|----------------------------------|<br/>-- |   0   | CEO          | /CEO                             |<br/>-- |   1   | VP-Eng       | /CEO/VP-Eng                      |<br/>-- |   2   | Backend      | /CEO/VP-Eng/Backend              |<br/>-- |   3   | Go Squad     | /CEO/VP-Eng/Backend/Go Squad     |<br/>-- |   3   | Java Squad   | /CEO/VP-Eng/Backend/Java Squad   |<br/>-- |   2   | Frontend     | /CEO/VP-Eng/Frontend             |<br/>-- |   3   | React Squad  | /CEO/VP-Eng/Frontend/React Squad |<br/>-- |   1   | VP-Finance   | /CEO/VP-Finance                  |<br/>-- |   1   | VP-Sales     | /CEO/VP-Sales                    |<br/>-- |   2   | APAC Sales   | /CEO/VP-Sales/APAC Sales         |<br/>-- |   2   | EMEA Sales   | /CEO/VP-Sales/EMEA Sales         |</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">进阶：限制递归深度 + 子树查询</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// 只查询 VP-Engineering 的子树，最多展开 3 层</span><br/>CriteriaBuilder&lt;Tuple&gt; cb = cbf.create(em, Tuple.class)<br/>    .withRecursive(OrgTreeCTE.class)<br/>        .from(Department.class, \"d\")<br/>        .bind(\"id\").select(\"d.id\")<br/>        .bind(\"name\").select(\"d.name\")<br/>        .bind(\"parentId\").select(\"d.parent.id\")<br/>        .bind(\"level\").select(\"0\")<br/>        .bind(\"path\").select(\"CONCAT('/', d.name)\")<br/>        .where(\"d.id\").eq(vpEngId)    <span style=\"color:#6c7086;font-style:italic;\">// 子树根节点</span><br/>    .unionAll()<br/>        .from(Department.class, \"d\")<br/>        .from(OrgTreeCTE.class, \"t\")<br/>        .bind(\"id\").select(\"d.id\")<br/>        .bind(\"name\").select(\"d.name\")<br/>        .bind(\"parentId\").select(\"d.parent.id\")<br/>        .bind(\"level\").select(\"t.level + 1\")<br/>        .bind(\"path\").select(\"CONCAT(t.path, '/', d.name)\")<br/>        .where(\"d.parent.id\").eqExpression(\"t.id\")<br/>        .where(\"t.level\").lt(3)       <span style=\"color:#6c7086;font-style:italic;\">// 最多 3 层</span><br/>    .end()<br/>    .from(OrgTreeCTE.class, \"t\")<br/>    .select(\"t.level\").select(\"t.name\").select(\"t.path\")<br/>    .orderByAsc(\"t.path\");</p></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\">-- 子树查询 + 深度限制:<br/>WITH RECURSIVE OrgTreeCTE(...) AS (<br/>    SELECT d.id, d.name, d.parent_id, 0, CONCAT('/', d.name)<br/>    FROM departments d<br/>    WHERE d.id = 42          -- VP-Eng 的 ID<br/><br/>    UNION ALL<br/><br/>    SELECT d.id, d.name, d.parent_id, t.level + 1,<br/>           CONCAT(t.path, '/', d.name)<br/>    FROM departments d<br/>    JOIN OrgTreeCTE t ON d.parent_id = t.id<br/>    WHERE t.level &lt; 3       -- 递归深度限制 → 防止无限递归<br/>)<br/>SELECT t.level, t.name, t.path<br/>FROM OrgTreeCTE t<br/>ORDER BY t.path ASC</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.10 性能调优清单</h2></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">掌握了具体优化技巧后，需要一套系统化的检查流程。以下清单涵盖从查询层到基础设施层的完整优化维度。</p></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-12 性能优化决策树</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">21</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">1</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">2</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">5</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">3</p></section><p style=\"text-align:center;font-size:16px;color:#bbb;margin:0;line-height:1.2;\">↓</p><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">4</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">性能问题</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 查询慢？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 返回列过多？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ Entity View 精确投影<br/>见 21.1</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ SQL 条数过多？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ N+1 问题？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ @BatchFetch / Correlated<br/>见 21.2</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ 批量 DML<br/>见 21.5</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 深翻页？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ Keyset 分页<br/>见 21.3</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 复杂聚合？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ CTE + 窗口函数<br/>见 21.4 / 21.6</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ 检查索引和执行计划</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 内存压力？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ Entity View (无 L1 缓存)<br/>→ 调整连接池大小</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #e6a817;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">◇ 代码冗余？</p></section><section style=\"margin:4px auto;padding:8px 20px;max-width:85%;background:#f5f5f5;border:2px solid #1e6fff;border-radius:8px;text-align:center;\"><p style=\"margin:0;font-size:13px;font-weight:600;color:#1a1a2e;line-height:1.6;\">→ ViewFilter (软删除/租户)<br/>→ JpqlMacro (通用条件)</p></section></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n优化层检查项优化前优化后参考章节\n\n\n查询层SELECT 列数SELECT * (15+列)Entity View 精确投影 (3列)21.1\nSQL 条数 (N+1)101 条 SQL1–3 条 SQL21.2\n分页层深翻页性能OFFSET 99980 (~2.5s)WHERE id > ? (~5ms)21.3\n数据一致性OFFSET 漂移Keyset 无漂移21.3\n聚合层复杂报表嵌套子查询 3 层CTE 线性分解21.4\n窗口计算多次查询拼装单条 SQL 多维度21.6\nDML 层批量更新N 条 UPDATE1 条 UPDATE21.5\n数据归档SELECT → INSERT 循环INSERT...SELECT21.5\n基础设施连接池默认 10 连接按公式计算最优值21.10\n二级缓存未启用Entity View + 缓存联动21.10\n\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">Spring Data 集成性能最佳实践</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ✅ Spring Boot 配置 — Blaze-Persistence 性能调优</span><br/>@Configuration<br/>public class BlazePersistenceConfig {<br/><br/>    @Bean<br/>    public CriteriaBuilderFactory criteriaBuilderFactory(<br/>            EntityManagerFactory emf) {<br/>        CriteriaBuilderConfiguration config = Criteria.getDefault();<br/><br/>        <span style=\"color:#6c7086;font-style:italic;\">// 启用 COUNT 查询优化（分页时自动生成高效的 COUNT 查询）</span><br/>        config.setProperty(<br/>            ConfigurationProperties.RETURNING_CLAUSE_ENABLED, \"true\");<br/><br/>        <span style=\"color:#6c7086;font-style:italic;\">// 设置默认 BatchFetch size，避免全局 N+1</span><br/>        config.setProperty(<br/>            ConfigurationProperties.DEFAULT_BATCH_SIZE, \"100\");<br/><br/>        return config.createCriteriaBuilderFactory(emf);<br/>    }<br/><br/>    @Bean<br/>    public EntityViewManager entityViewManager(<br/>            CriteriaBuilderFactory cbf, EntityViewConfiguration evc) {<br/>        return evc.createEntityViewManager(cbf);<br/>    }<br/>}</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">连接池大小计算</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\"># HikariCP 连接池配置 (application.yml)</span><br/>spring:<br/>  datasource:<br/>    hikari:<br/><span style=\"color:#6c7086;font-style:italic;\">      # 最优连接数 = CPU核心数 × 2 + 磁盘数</span><br/><span style=\"color:#6c7086;font-style:italic;\">      # 8核服务器 + 1块SSD = 8 × 2 + 1 = 17</span><br/>      maximum-pool-size: 17<br/>      minimum-idle: 5<br/><span style=\"color:#6c7086;font-style:italic;\">      # 连接超时: 尽快发现问题</span><br/>      connection-timeout: 5000<br/><span style=\"color:#6c7086;font-style:italic;\">      # 空闲超时: 避免长时间占用</span><br/>      idle-timeout: 300000<br/><span style=\"color:#6c7086;font-style:italic;\">      # 最大生命周期: 比数据库 wait_timeout 短</span><br/>      max-lifetime: 1800000<br/><span style=\"color:#6c7086;font-style:italic;\">      # 泄漏检测阈值: 超过 30s 未归还连接则告警</span><br/>      leak-detection-threshold: 30000<br/><br/>  jpa:<br/>    properties:<br/>      hibernate:<br/><span style=\"color:#6c7086;font-style:italic;\">        # 二级缓存 — 只缓存不常变的参考数据</span><br/>        cache:<br/>          use_second_level_cache: true<br/>          region.factory_class: org.hibernate.cache.jcache.JCacheRegionFactory<br/><span style=\"color:#6c7086;font-style:italic;\">        # JDBC 批处理大小</span><br/>        jdbc:<br/>          batch_size: 50<br/><span style=\"color:#6c7086;font-style:italic;\">        # 排序 INSERT / UPDATE 以减少死锁</span><br/>        order_inserts: true<br/>        order_updates: true</p></section>\n<section><h2 style=\"font-size:20px;font-weight:700;color:#1a1a2e;border-bottom:2px solid #1e6fff;padding-bottom:6px;margin:36px 0 16px;\">21.11 陷阱与限制</h2></section>\n<section style=\"background:#f5f5f5;border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:16px 0;overflow-x:auto;\"><p style=\"font-size:11px;font-weight:700;color:#888;text-transform:uppercase;letter-spacing:1px;margin-bottom:12px;\">Fig 21-13 常见优化陷阱检查清单</p><p style=\"font-size:13px;color:#2b2b2b;line-height:2;margin:8px 0;\">\n\n陷阱 1: em.find()\n❌ em.find() 不经过 Entity View，仍然 SELECT *\n✅ 使用 evm.find()\n\n\n陷阱 2: 批量 DML + L1 缓存\n❌ L1 缓存不同步，已加载的实体未更新\n✅ 批量 DML 后 em.clear() 清除缓存\n\n\n陷阱 3: Keyset + 非唯一排序\n❌ status 不唯一，Keyset 结果不确定\n✅ 末尾追加唯一列 .orderByDesc('id')\n\n\n陷阱 4: CTE + MySQL 5.x\n❌ MySQL 5.x 不支持 CTE，递归 CTE 无法降级\n✅ 升级到 MySQL 8.0+ 或使用 PostgreSQL\n\n\n陷阱 5: ViewFilter 遗漏\n❌ 软删除数据泄漏，已删除订单出现在列表\n✅ 用 ViewFilterProvider 自动激活过滤器\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 1：Entity View 不等于 em.find()</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 常见错误: 用 em.find() 查询单个实体 → 绕过 Entity View</span><br/>Order order = em.find(Order.class, orderId);<br/><span style=\"color:#6c7086;font-style:italic;\">// → SELECT * FROM orders WHERE id = ? (全字段)</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 正确: 使用 evm.find() 获取 View 投影</span><br/>OrderView view = evm.find(em, OrderView.class, orderId);<br/><span style=\"color:#6c7086;font-style:italic;\">// → SELECT o.id, o.status, c.name FROM orders o</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   JOIN customers c ON o.customer_id = c.id</span><br/><span style=\"color:#6c7086;font-style:italic;\">//   WHERE o.id = ?</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 2：批量 DML 后一级缓存不同步</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// ❌ 陷阱: 批量 UPDATE 后已加载的实体仍是旧值</span><br/>Order order = em.find(Order.class, 1L);<br/>System.out.println(order.getStatus()); <span style=\"color:#6c7086;font-style:italic;\">// → PENDING</span><br/><br/>cbf.update(em, Order.class, \"o\")<br/>    .set(\"o.status\", OrderStatus.CANCELLED)<br/>    .where(\"o.id\").eq(1L)<br/>    .executeUpdate();<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// order 对象仍在 L1 缓存中，值未更新!</span><br/>System.out.println(order.getStatus()); <span style=\"color:#6c7086;font-style:italic;\">// → 仍然是 PENDING ❌</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// ✅ 解决: 批量 DML 后清除一级缓存</span><br/>cbf.update(em, Order.class, \"o\")<br/>    .set(\"o.status\", OrderStatus.CANCELLED)<br/>    .where(\"o.id\").eq(1L)<br/>    .executeUpdate();<br/>em.clear();  <span style=\"color:#6c7086;font-style:italic;\">// 清除 L1 缓存</span><br/><br/>Order refreshed = em.find(Order.class, 1L);<br/>System.out.println(refreshed.getStatus()); <span style=\"color:#6c7086;font-style:italic;\">// → CANCELLED ✅</span></p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">陷阱 3：什么时候不该用 Blaze-Persistence</h3></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">\n\n\n场景推荐方案原因\n\n\n超简单 CRUD (单表、无关联)Spring Data JPA 原生引入框架的复杂度不值得\n存储过程/原生 SQL 强依赖MyBatis / jOOQBlaze-Persistence 基于 JPQL，无法调用存储过程\nNoSQL 数据库Spring Data MongoDB 等Blaze-Persistence 只支持关系型数据库\n极致性能 (微秒级)JDBC + 手写 SQL任何 ORM 抽象都有开销\n遗留系统表结构极不规范MyBatis XML 映射JPA 实体映射困难时，先解决映射问题\n\n\n</p></section>\n<section><h3 style=\"font-size:17px;font-weight:600;color:#1e6fff;margin:24px 0 10px;\">JPA Provider 特定注意事项</h3></section>\n<section><p style=\"background:#1e1e2e;border-radius:8px;padding:16px 20px;margin:14px 0;overflow-x:auto;font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;line-height:1.8;color:#cdd6f4;white-space:pre-wrap;word-break:break-all;\"><span style=\"color:#6c7086;font-style:italic;\">// Hibernate 特定: 启用 hibernate.query.plan_cache_max_size</span><br/><span style=\"color:#6c7086;font-style:italic;\">// Blaze-Persistence 生成大量动态 JPQL → 查询计划缓存可能溢出</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 建议值: 4096 (默认 2048)</span><br/>properties.put(\"hibernate.query.plan_cache_max_size\", \"4096\");<br/><br/><span style=\"color:#6c7086;font-style:italic;\">// EclipseLink 特定: 共享缓存与批量 DML 冲突</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 批量 UPDATE/DELETE 不会通知 EclipseLink L2 缓存</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 解决: 批量 DML 后手动失效相关缓存</span><br/>em.getEntityManagerFactory().getCache()<br/>    .evict(Order.class);  <span style=\"color:#6c7086;font-style:italic;\">// 失效 Order 的 L2 缓存</span><br/><br/><span style=\"color:#6c7086;font-style:italic;\">// Hibernate 6.x / Jakarta EE 10:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// Blaze-Persistence 1.6+ 同时支持 javax.persistence 和 jakarta.persistence</span><br/><span style=\"color:#6c7086;font-style:italic;\">// 检查依赖版本匹配:</span><br/><span style=\"color:#6c7086;font-style:italic;\">// blaze-persistence-integration-hibernate-6.2 → Hibernate 6.2+</span><br/><span style=\"color:#6c7086;font-style:italic;\">// blaze-persistence-integration-hibernate-5.6 → Hibernate 5.6</span></p></section>\n<section style=\"background:#f5f5f5;border:1px solid #1e6fff22;border-radius:10px;padding:20px 22px;margin:36px 0 16px;\"><p style=\"font-size:18px;font-weight:700;color:#1e6fff;margin:0 0 12px;\">📋 本章小结</p><ul style=\"margin:8px 0 12px 20px;color:#2b2b2b;\"><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Entity View 精确投影</strong> 将 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">SELECT *</code> 裁剪为只查询需要的列——减少 80%+ 的网络传输数据量，启用覆盖索引扫描，消除 EntityManager 一级缓存的内存压力</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">N+1 问题</strong>有三种解决方案：<code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">@BatchFetch</code> 最简单（一行注解），Correlated SUBSELECT 最均衡（2 条 SQL 无膨胀），JOIN 获取最激进（1 条 SQL 但有笛卡尔积）</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">Keyset 分页</strong>用 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">WHERE id > ?</code> 替代 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">OFFSET</code>——第 5000 页的性能与第 1 页相同 (~5ms)，而 OFFSET 分页在深翻页时性能下降 500 倍</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">CTE</strong> 将嵌套 3 层的子查询分解为线性命名步骤——提高 SQL 可读性，让优化器有更大的优化空间</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">批量 DML</strong> 用 1 条 SQL 替代 N 条——批量 UPDATE/DELETE 比逐条操作快 300 倍，INSERT...SELECT 在数据库内部完成数据迁移，不经过应用层</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">窗口函数</strong>让报表查询在单条 SQL 中返回日销售额、7 日移动平均、累计总额、日环比 4 个维度——无需多次查询拼装</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">@ViewFilter</strong> 将软删除和多租户条件抽为命名过滤器——一次定义、查询时按名称激活，配合 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">ViewFilterProvider</code> 实现完全透明的条件注入</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">全文搜索</strong>通过 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">JpqlFunction</code> 扩展点将 PostgreSQL 的 <code style=\"font-family:Menlo,Consolas,'Courier New',monospace;font-size:13px;background:#f5f5f5;padding:2px 6px;border-radius:4px;color:#333;\">tsvector/tsquery</code> 集成到 Blaze-Persistence——在 JPQL 层面使用，SQL 渲染时输出原生语法</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">递归 CTE</strong> 在单条 SQL 中展开任意深度的树形结构——组织架构、分类目录、评论回复等场景不再需要应用层递归查询</li><li style=\"margin-bottom:5px;font-size:14px;\"><strong style=\"color:#1a1a2e;font-weight:700;\">生产调优</strong>需要关注连接池大小（CPU核心数 × 2 + 磁盘数）、查询计划缓存、批量 DML 后的缓存失效、Keyset 排序列的唯一性</li></ul><p style=\"font-size:13px;color:#888;margin-top:10px;padding-top:10px;border-top:1px solid #e5e7eb;\">下一章 <span style=\"color:#1e6fff;\">第 22 章 · Spring Boot + Blaze-Persistence 实战：项目搭建与基础 CRUD</span> 将进入「实战篇」——以一个完整的电商订单管理系统为载体，将前 21 章的知识融合为可运行的生产级代码，从 Maven 配置到 JPA Entity，从 Entity View 精确投影到 RESTful API 暴露。</p></section>\n<section><p style=\"font-size:15px;color:#2b2b2b;line-height:1.8;margin:0 0 12px;\">© 2026 图解 Blaze-Persistence · 第 21 章</p></section>";
  await page.waitForSelector('.ProseMirror', { timeout: 15000 });
  if (title) {
    var ti = page.locator('textarea[placeholder="请在这里输入标题"]');
    await ti.fill(title);
    await page.waitForTimeout(300);
  }
  await page.evaluate((h) => {
    var pm = document.querySelector('.ProseMirror');
    pm.focus();
    var dt = new DataTransfer();
    dt.setData('text/html', h);
    var ev = new ClipboardEvent('paste', {bubbles:true, cancelable:true, clipboardData:dt});
    pm.dispatchEvent(ev);
  }, html);
  await page.waitForTimeout(1500);
  var enableBtns = page.locator('label:has-text("开启")');
  var cnt = await enableBtns.count();
  for (var i = 0; i < cnt; i++) {
    try {
      var b = enableBtns.nth(i);
      if (await b.isVisible({ timeout: 500 })) await b.click({ timeout: 1000 });
    } catch(e) {}
  }
  await page.waitForTimeout(500);
  var saveBtn = page.getByRole('button', { name: '保存为草稿' });
  await saveBtn.click();
  await page.waitForTimeout(2000);
  return title + ' -> saved';
}